AR_ITEM = {
    **SHARED,
    "lang": {"S": "ar"},
    "langStoryId": {"S": "ar#lots-of-the-ten"},
    "title": {"S": "\u0642\u064f\u0631\u0652\u0639\u064e\u0629 \u0627\u0644\u0639\u064e\u0634\u064e\u0631\u064e\u0629"},
    "subtitle": {
        "S": "\u0623\u062d\u062f \u0639\u0634\u0631 \u0634\u064e\u0642\u0652\u0641\u064e\u0629\u064b \u0641\u064e\u062e\u0651\u0627\u0631\u064a\u0651\u0629\u060c \u062b\u0644\u0627\u062b \u062c\u064f\u062b\u064e\u062b\u060c \u0648\u0636\u064e\u0641\u064a\u0631\u0629 \u0634\u064e\u0639\u0652\u0631 \u0627\u0645\u0631\u0623\u0629 \u2014 \u0627\u0644\u0627\u0643\u062a\u0634\u0627\u0641\u0627\u062a \u0627\u0644\u062a\u064a \u0623\u062b\u0628\u062a\u062a \u0623\u0633\u0637\u0648\u0631\u0629 \u0645\u064e\u0633\u0627\u062f\u0627 \u0648\u0634\u0643\u0651\u0643\u062a \u0641\u064a\u0647\u0627 \u0641\u064a \u0622\u0646\u064d \u0648\u0627\u062d\u062f"
    },
    "excerpt": {
        "S": "\u062d\u064a\u0646 \u0639\u062b\u0631 \u0639\u064f\u0644\u0645\u0627\u0621 \u0627\u0644\u0622\u062b\u0627\u0631 \u0639\u0644\u0649 \u0623\u062d\u062f \u0639\u0634\u0631 \u0634\u064e\u0642\u0652\u0641\u064e\u0629\u064b \u0645\u0646\u0642\u0648\u0634\u0629 \u0628\u0623\u0633\u0645\u0627\u0621 \u2014 \u0628\u064a\u0646\u0647\u0627 \u0648\u0627\u062d\u062f\u0629 \u062a\u062d\u0645\u0644 \u0627\u0633\u0645 \u00ab\u0628\u0646 \u064a\u0627\u0626\u064a\u0631\u00bb \u2014 \u0638\u0646\u0651\u0648\u0627 \u0623\u0646\u0651\u0647\u0645 \u0623\u0645\u0633\u0643\u0648\u0627 \u0628\u062f\u0644\u064a\u0644\u064d \u0645\u0646 \u0622\u062e\u0631 \u0644\u064a\u0644\u0629 \u0639\u0644\u0649 \u0645\u064e\u0633\u0627\u062f\u0627. \u0644\u0643\u0646\u0651 \u0627\u0644\u062d\u0642\u064a\u0642\u0629 \u0643\u0627\u0646\u062a \u0623\u0639\u0642\u062f \u0628\u0643\u062b\u064a\u0631."
    },
    "paragraphs": make_paragraphs(
        [
            # P1
            "\u0641\u064a \u0639\u0627\u0645 \u0661\u0669\u0666\u0663\u060c \u0635\u064e\u0639\u0650\u062f\u064e \u064a\u0650\u063a\u0627\u0626\u064a\u0644 \u064a\u0627\u062f\u064a\u0646 \u0625\u0644\u0649 \u0642\u0645\u0651\u0629 \u0645\u064e\u0633\u0627\u062f\u0627 \u0648\u0645\u0639\u0647 \u0622\u0644\u0627\u0641 \u0627\u0644\u0645\u062a\u0637\u0648\u0651\u0639\u064a\u0646 \u0645\u0646 \u062b\u0645\u0627\u0646\u064a\u0629 \u0648\u0639\u0634\u0631\u064a\u0646 \u0628\u0644\u062f\u064b\u0627. \u064a\u0627\u062f\u064a\u0646 \u0644\u0645 \u064a\u0643\u0646 \u0645\u062c\u0631\u0651\u062f \u0639\u0627\u0644\u0645 \u0622\u062b\u0627\u0631 \u2014 \u0643\u0627\u0646 \u0642\u0627\u0626\u062f \u0627\u0644\u062c\u064a\u0634 \u0627\u0644\u0625\u0633\u0631\u0627\u0626\u064a\u0644\u064a \u0641\u064a \u062d\u0631\u0628 \u0661\u0669\u0664\u0668. \u0627\u0644\u0622\u0646 \u062c\u0627\u0621 \u064a\u0646\u0628\u0634 \u0641\u064a \u0627\u0644\u062d\u0635\u0646 \u0627\u0644\u0635\u062d\u0631\u0627\u0648\u064a \u0627\u0644\u0630\u064a \u0627\u062e\u062a\u0627\u0631 \u0641\u064a\u0647 \u0646\u062d\u0648 \u0623\u0644\u0641 \u064a\u0647\u0648\u062f\u064a\u0651 \u0627\u0644\u0645\u0648\u062a\u064e \u0639\u0644\u0649 \u0627\u0644\u0627\u0633\u062a\u0633\u0644\u0627\u0645 \u0644\u0631\u0648\u0645\u0627 \u0633\u0646\u0629 \u0667\u0663 \u0645\u064a\u0644\u0627\u062f\u064a\u0629. \u0627\u0644\u0645\u0624\u0631\u0651\u062e \u064a\u0648\u0633\u064a\u0641\u0648\u0633 \u0632\u0639\u0645 \u0623\u0646\u0651 \u0639\u0634\u0631\u0629 \u0631\u062c\u0627\u0644 \u0627\u062e\u062a\u064a\u0631\u0648\u0627 \u0628\u0627\u0644\u0642\u064f\u0631\u0639\u0629 \u0644\u064a\u0642\u062a\u0644\u0648\u0627 \u0627\u0644\u062c\u0645\u064a\u0639. \u064a\u0627\u062f\u064a\u0646 \u0623\u0631\u0627\u062f \u0623\u0646 \u064a\u062c\u062f \u062a\u0644\u0643 \u0627\u0644\u0642\u064f\u0631\u0639\u0629.",
            # P2
            "\u0648\u0648\u062c\u062f \u0645\u0627 \u0623\u0630\u0647\u0644 \u0627\u0644\u0639\u0627\u0644\u0645. \u0642\u0631\u0628 \u0627\u0644\u0628\u0648\u0651\u0627\u0628\u0629 \u0627\u0644\u062c\u0646\u0648\u0628\u064a\u0629\u060c \u0623\u062e\u0631\u062c \u0641\u0631\u064a\u0642\u0647 \u0623\u062d\u062f \u0639\u0634\u0631 \u0634\u064e\u0642\u0652\u0641\u064e\u0629\u064b \u0641\u062e\u0651\u0627\u0631\u064a\u0629 \u0645\u0646 \u0627\u0644\u062a\u0631\u0627\u0628\u060c \u0639\u0644\u0649 \u0643\u0644\u0651 \u0648\u0627\u062d\u062f\u0629 \u0627\u0633\u0645\u064c \u0645\u062d\u0641\u0648\u0631. \u0625\u062d\u062f\u0627\u0647\u0627 \u0643\u064f\u062a\u0628 \u0639\u0644\u064a\u0647\u0627 \u00ab\u0628\u0646 \u064a\u0627\u0626\u064a\u0631\u00bb \u2014 \u0627\u0633\u0645 \u0625\u0644\u0639\u0627\u0632\u0627\u0631 \u0628\u0646 \u064a\u0627\u0626\u064a\u0631\u060c \u0627\u0644\u0642\u0627\u0626\u062f \u0627\u0644\u0630\u064a \u0623\u0642\u0646\u0639 \u0642\u0648\u0645\u0647 \u0628\u0627\u0644\u0645\u0648\u062a \u0628\u062f\u0644 \u0627\u0644\u0639\u0628\u0648\u062f\u064a\u0629. \u0643\u062a\u0628 \u064a\u0627\u062f\u064a\u0646: \u00ab\u062a\u062e\u064a\u0651\u0644\u0648\u0627 \u0634\u0639\u0648\u0631 \u0645\u0646 \u0633\u062d\u0628 \u0647\u0630\u0647 \u0627\u0644\u0642\u064f\u0631\u0639\u0629.\u00bb \u0627\u0644\u0639\u0627\u0644\u0645 \u062a\u0633\u0645\u0651\u0631 \u2014 \u0627\u0644\u062f\u0644\u064a\u0644 \u0627\u0644\u0645\u0627\u062f\u0651\u064a \u0639\u0644\u0649 \u0623\u0634\u062f\u0651 \u0644\u064a\u0627\u0644\u064a \u0627\u0644\u062a\u0627\u0631\u064a\u062e \u0627\u0644\u064a\u0647\u0648\u062f\u064a \u062f\u0631\u0627\u0645\u0627\u062a\u064a\u0643\u064a\u0629\u064b\u060c \u0645\u0644\u0642\u064b\u0649 \u0628\u064a\u0646 \u0627\u0644\u062d\u062c\u0627\u0631\u0629.",
            # P3
            "\u0644\u0643\u0646\u0651 \u0627\u0644\u0639\u0644\u0645\u0627\u0621 \u0644\u0645 \u064a\u064f\u0633\u0644\u0651\u0645\u0648\u0627 \u0628\u0633\u0647\u0648\u0644\u0629. \u0627\u0644\u0634\u0651\u064f\u0642\u064e\u0641 \u0623\u062d\u062f \u0639\u0634\u0631 \u0644\u0627 \u0639\u0634\u0631\u0629. \u0648\u00ab\u0628\u0646 \u064a\u0627\u0626\u064a\u0631\u00bb \u0643\u0627\u0646 \u0627\u0633\u0645\u064b\u0627 \u0645\u0646\u062a\u0634\u0631\u064b\u0627 \u0641\u064a \u0627\u0644\u0642\u0631\u0646 \u0627\u0644\u0623\u0648\u0651\u0644 \u2014 \u0643\u0623\u0646 \u062a\u062c\u062f \u0627\u0633\u0645 \u00ab\u0645\u062d\u0645\u062f \u0623\u062d\u0645\u062f\u00bb \u0641\u064a \u062d\u0641\u0631\u064a\u0651\u0629 \u0627\u0644\u064a\u0648\u0645. \u0645\u0626\u0627\u062a \u0627\u0644\u0634\u0651\u064f\u0642\u064e\u0641 \u0627\u0644\u0645\u0634\u0627\u0628\u0647\u0629 \u0638\u0647\u0631\u062a \u0641\u064a \u0645\u064e\u0633\u0627\u062f\u0627 \u0648\u0627\u0633\u062a\u064f\u062e\u062f\u0645\u062a \u0644\u0623\u063a\u0631\u0627\u0636 \u0639\u0627\u062f\u064a\u0629 \u0643\u062c\u062f\u0627\u0648\u0644 \u0627\u0644\u0639\u0645\u0644 \u0648\u062a\u0648\u0632\u064a\u0639 \u0627\u0644\u0637\u0639\u0627\u0645. \u0648\u064a\u0648\u0633\u064a\u0641\u0648\u0633 \u0646\u0641\u0633\u0647 \u0643\u062a\u0628 \u062a\u062d\u062a \u0631\u0639\u0627\u064a\u0629 \u0627\u0644\u0623\u0628\u0627\u0637\u0631\u0629 \u0627\u0644\u0630\u064a\u0646 \u062f\u0645\u0651\u0631\u0648\u0627 \u0627\u0644\u0642\u062f\u0633 \u2014 \u0627\u0646\u062a\u062d\u0627\u0631\u064c \u0628\u0637\u0648\u0644\u064a\u0651 \u064a\u0635\u0646\u0639 \u062d\u0643\u0627\u064a\u0629\u064b \u0623\u0641\u0636\u0644 \u0628\u0643\u062b\u064a\u0631 \u0645\u0646 \u0646\u0647\u0627\u064a\u0629 \u0641\u0648\u0636\u0648\u064a\u0629.",
            # P4
            "\u062b\u0645\u0651 \u0638\u0647\u0631\u062a \u0627\u0644\u062c\u064f\u062b\u064e\u062b. \u0641\u064a \u062d\u0645\u0651\u0627\u0645 \u0627\u0644\u0642\u0635\u0631 \u0627\u0644\u0634\u0645\u0627\u0644\u064a\u060c \u0643\u0634\u0641 \u0627\u0644\u062d\u0641\u0651\u0627\u0631\u0648\u0646 \u0639\u0646 \u062b\u0644\u0627\u062b\u0629 \u0647\u064a\u0627\u0643\u0644 \u0639\u0638\u0645\u064a\u0629: \u0634\u0627\u0628\u0651 \u0641\u064a \u0627\u0644\u0639\u0634\u0631\u064a\u0646\u060c \u0641\u062a\u0627\u0629 \u0641\u064a \u0627\u0644\u062b\u0627\u0645\u0646\u0629 \u0639\u0634\u0631\u0629\u060c \u0648\u0637\u0641\u0644. \u0628\u062c\u0627\u0646\u0628 \u0627\u0644\u0641\u062a\u0627\u0629 \u0648\u062c\u062f\u0648\u0627 \u0636\u064e\u0641\u064a\u0631\u0629 \u0634\u0639\u0631 \u2014 \u0633\u0644\u064a\u0645\u0629 \u0628\u0639\u062f \u0623\u0644\u0641\u064e\u064a \u0633\u0646\u0629\u060c \u062d\u0641\u0638\u0647\u0627 \u062c\u0641\u0627\u0641 \u0627\u0644\u0635\u062d\u0631\u0627\u0621 \u0627\u0644\u0645\u064f\u0637\u0644\u064e\u0642. \u0636\u0641\u0631\u062a \u0634\u0639\u0631\u0647\u0627 \u0648\u0647\u064a \u062a\u0639\u0644\u0645 \u0623\u0646\u0651\u0647\u0627 \u062a\u0645\u0648\u062a. \u0635\u0648\u0631\u0629 \u0644\u0627 \u062a\u062e\u0631\u062c \u0645\u0646 \u0627\u0644\u0630\u0647\u0646. \u0644\u0643\u0646\u0651 \u0639\u0638\u0627\u0645 \u062e\u0646\u0627\u0632\u064a\u0631 \u0648\u064f\u062c\u062f\u062a \u0642\u0631\u0628\u0647\u0645. \u0627\u0644\u064a\u0647\u0648\u062f \u0644\u0645 \u064a\u064f\u0631\u0628\u0651\u0648\u0627 \u062e\u0646\u0627\u0632\u064a\u0631. \u0627\u0644\u0631\u0648\u0645\u0627\u0646 \u0641\u0639\u0644\u0648\u0627. \u0641\u0645\u0646 \u0647\u0624\u0644\u0627\u0621 \u062d\u0642\u064b\u0651\u0627\u061f",
            # P5
            "\u0625\u0633\u0631\u0627\u0626\u064a\u0644 \u0623\u062c\u0627\u0628\u062a \u0628\u0627\u0644\u0633\u064a\u0627\u0633\u0629 \u0644\u0627 \u0628\u0627\u0644\u0639\u0644\u0645. \u0641\u064a \u0639\u0627\u0645 \u0661\u0669\u0666\u0669\u060c \u0646\u0627\u0644 \u0633\u0628\u0639\u064c \u0648\u0639\u0634\u0631\u0648\u0646 \u0645\u062c\u0645\u0648\u0639\u0629 \u0631\u064f\u0641\u0627\u062a \u062c\u0646\u0627\u0632\u0629\u064b \u0639\u0633\u0643\u0631\u064a\u0629\u064b \u0643\u0627\u0645\u0644\u0629 \u0639\u0644\u0649 \u0633\u0641\u0648\u062d \u0645\u064e\u0633\u0627\u062f\u0627 \u2014 \u062a\u0648\u0627\u0628\u064a\u062a \u0645\u0644\u0641\u0648\u0641\u0629 \u0628\u0627\u0644\u0623\u0639\u0644\u0627\u0645 \u0648\u0637\u0644\u0642\u0627\u062a \u062a\u062d\u064a\u0651\u0629. \u0627\u0644\u062f\u0648\u0644\u0629 \u0639\u0627\u0645\u0644\u062a \u0643\u062d\u0642\u064a\u0642\u0629 \u0645\u0627 \u0639\u062c\u0632 \u0639\u0644\u0645 \u0627\u0644\u0622\u062b\u0627\u0631 \u0639\u0646 \u0625\u062b\u0628\u0627\u062a\u0647. \u0644\u0627\u062d\u0642\u064b\u0627 \u0643\u0634\u0641 \u0639\u0627\u0644\u0645 \u0627\u0644\u0627\u062c\u062a\u0645\u0627\u0639 \u0646\u062d\u0645\u0627\u0646 \u0628\u0646 \u064a\u0647\u0648\u062f\u0627 \u0623\u0646\u0651 \u0627\u0644\u0643\u062a\u0628 \u0627\u0644\u0645\u062f\u0631\u0633\u064a\u0629 \u0623\u062e\u0641\u062a \u062d\u0642\u064a\u0642\u0629 \u0645\u064f\u0632\u0639\u062c\u0629: \u0627\u0644\u0645\u062f\u0627\u0641\u0639\u0648\u0646 \u0639\u0646 \u0645\u064e\u0633\u0627\u062f\u0627 \u0630\u0628\u062d\u0648\u0627 \u0633\u0628\u0639\u0645\u0626\u0629 \u064a\u0647\u0648\u062f\u064a\u0651 \u0645\u0646 \u0642\u0631\u064a\u0629 \u0645\u062c\u0627\u0648\u0631\u0629 \u0642\u0628\u0644 \u0623\u0646 \u064a\u0644\u062c\u0624\u0648\u0627 \u0625\u0644\u0649 \u0627\u0644\u062c\u0628\u0644. \u0627\u0644\u0623\u0633\u0637\u0648\u0631\u0629 \u0643\u0627\u0646\u062a \u0623\u0646\u0641\u0639 \u0645\u0646 \u0627\u0644\u0641\u0648\u0636\u0649.",
            # P6
            "\u0644\u0643\u0646 \u0648\u0633\u0637 \u0643\u0644\u0651 \u0647\u0630\u0627 \u0627\u0644\u062c\u062f\u0644\u060c \u0643\u0634\u0641 \u0627\u0644\u062a\u0646\u0642\u064a\u0628 \u0639\u0646 \u0634\u064a\u0621 \u0644\u0627 \u064a\u0642\u0628\u0644 \u0627\u0644\u062a\u0623\u0648\u064a\u0644. \u0628\u064a\u0646 \u0627\u0644\u0645\u062e\u0637\u0648\u0637\u0627\u062a \u0641\u064a \u0627\u0644\u0623\u0646\u0642\u0627\u0636 \u0638\u0647\u0631\u062a \u0642\u0637\u0639\u0629 \u0645\u0646 \u0633\u0650\u0641\u0631 \u062d\u0632\u0642\u064a\u0627\u0644 \u0663\u0667 \u2014 \u0631\u0624\u064a\u0627 \u0627\u0644\u0646\u0628\u064a\u0651 \u0644\u0648\u0627\u062f\u064d \u0645\u0644\u064a\u0621 \u0628\u0627\u0644\u0639\u0638\u0627\u0645 \u0627\u0644\u064a\u0627\u0628\u0633\u0629 \u062d\u064a\u062b \u064a\u0633\u0623\u0644 \u0627\u0644\u0644\u0647: \u00ab\u0623\u062a\u062d\u064a\u0627 \u0647\u0630\u0647 \u0627\u0644\u0639\u0638\u0627\u0645\u061f\u00bb \u0646\u0635\u0651\u064c \u0639\u0646 \u0628\u0639\u062b \u0627\u0644\u0623\u0645\u0645\u060c \u0641\u064a \u0627\u0644\u0645\u0643\u0627\u0646 \u0627\u0644\u0630\u064a \u0645\u0627\u062a\u062a \u0641\u064a\u0647 \u0645\u0642\u0627\u0648\u0645\u0629 \u0623\u0645\u0651\u0629. \u062b\u0645\u0651 \u0641\u064a \u0639\u0627\u0645 \u0662\u0660\u0660\u0665\u060c \u0632\u0631\u0639 \u0639\u0644\u0645\u0627\u0621 \u0628\u0630\u0631\u0629 \u0646\u062e\u064a\u0644\u064d \u0645\u0646 \u062d\u0641\u0631\u064a\u0651\u0627\u062a \u064a\u0627\u062f\u064a\u0646 \u2014 \u0639\u0645\u0631\u0647\u0627 \u0623\u0644\u0641\u0627 \u0639\u0627\u0645. \u0646\u0628\u062a\u062a. \u0648\u0646\u0645\u062a. \u0648\u0633\u0645\u0651\u0648\u0647\u0627 \u00ab\u0645\u064e\u062a\u0648\u0634\u0627\u0644\u064e\u062d.\u00bb",
            # P7
            "\u064a\u0642\u0648\u0644\u0648\u0646 \u00ab\u064a\u064e\u0648\u0652\u0645\u064e\u0626\u0650\u0630\u064d \u062a\u064f\u062d\u064e\u062f\u0651\u0650\u062b\u064f \u0623\u064e\u062e\u0652\u0628\u064e\u0627\u0631\u064e\u0647\u064e\u0627\u00bb \u2014 \u0644\u0643\u0646\u0651 \u0623\u0631\u0636 \u0645\u064e\u0633\u0627\u062f\u0627 \u062d\u062f\u0651\u062b\u062a\u0646\u0627 \u0628\u0623\u062e\u0628\u0627\u0631\u0647\u0627 \u0648\u0644\u0645 \u0646\u0633\u062a\u0637\u0639 \u0623\u0646 \u0646\u062c\u0632\u0645: \u0623\u0635\u064e\u062f\u064e\u0642\u064e\u062a\u0646\u0627\u060c \u0623\u0645 \u0646\u062d\u0646 \u0645\u0646 \u0643\u062a\u0628\u0646\u0627 \u0644\u0647\u0627 \u0627\u0644\u0633\u064a\u0646\u0627\u0631\u064a\u0648\u061f \u0627\u0644\u0634\u0651\u064f\u0642\u064e\u0641 \u0631\u0628\u0651\u0645\u0627 \u0644\u064a\u0633\u062a \u0627\u0644\u0642\u064f\u0631\u0639\u0629. \u0627\u0644\u0639\u0638\u0627\u0645 \u0631\u0628\u0651\u0645\u0627 \u0644\u064a\u0633\u062a \u0639\u0638\u0627\u0645 \u0627\u0644\u0645\u062f\u0627\u0641\u0639\u064a\u0646. \u0627\u0644\u062e\u064f\u0637\u064e\u0628 \u0631\u0628\u0651\u0645\u0627 \u0644\u0645 \u062a\u064f\u0644\u0642\u064e \u0642\u0637\u0651. \u0644\u0643\u0646\u0651 \u0627\u0644\u0645\u062e\u0637\u0648\u0637\u0627\u062a \u0643\u0627\u0646\u062a \u062d\u0642\u064a\u0642\u064a\u0629 \u2014 \u0642\u0631\u0623\u0647\u0627 \u0646\u0627\u0633\u064c \u062d\u0642\u064a\u0642\u064a\u0651\u0648\u0646 \u0641\u064a \u0643\u0646\u064a\u0633\u064d \u062d\u0642\u064a\u0642\u064a\u0651 \u0641\u0648\u0642 \u062c\u0628\u0644 \u062d\u0642\u064a\u0642\u064a\u0651. \u0648\u062a\u0644\u0643 \u0627\u0644\u0628\u0630\u0631\u0629 \u0643\u0627\u0646\u062a \u062d\u0642\u064a\u0642\u064a\u0629\u060c \u0645\u062f\u0641\u0648\u0646\u0629 \u0623\u0644\u0641\u064e\u064a \u0639\u0627\u0645 \u062a\u062d\u062a \u0627\u0644\u0623\u0646\u0642\u0627\u0636 \u062a\u0646\u062a\u0638\u0631 \u0645\u0627\u0621\u064b \u0648\u0646\u0648\u0631\u064b\u0627. \u0623\u062a\u062d\u064a\u0627 \u0647\u0630\u0647 \u0627\u0644\u0639\u0638\u0627\u0645\u061f \u0641\u064a \u0645\u064e\u0633\u0627\u062f\u0627\u060c \u062d\u062a\u0651\u0649 \u0627\u0644\u0628\u0630\u0648\u0631 \u062a\u062c\u064a\u0628: \u0646\u0639\u0645.",
        ]
    ),
    "moralOrLesson": {
        "S": "\u0627\u0644\u062d\u062f\u0651 \u0627\u0644\u0641\u0627\u0635\u0644 \u0628\u064a\u0646 \u0627\u0643\u062a\u0634\u0627\u0641 \u0627\u0644\u0645\u0627\u0636\u064a \u0648\u0627\u062e\u062a\u0631\u0627\u0639\u0647 \u0623\u064e\u0631\u064e\u0642\u0651 \u0645\u0645\u0651\u0627 \u0646\u0648\u062f\u0651 \u0623\u0646 \u0646\u0639\u062a\u0631\u0641. \u0643\u0644\u0651 \u0639\u0627\u0644\u0645 \u0622\u062b\u0627\u0631\u064d \u064a\u0646\u062a\u0632\u0639 \u0642\u0637\u0639\u0629\u064b \u0645\u0646 \u0627\u0644\u0623\u0631\u0636 \u064a\u062e\u062a\u0627\u0631 \u0623\u064a\u0651 \u0642\u0635\u0651\u0629 \u064a\u0631\u0648\u064a\u0647\u0627 \u2014 \u0648\u0627\u0644\u0642\u0635\u0635 \u0627\u0644\u062a\u064a \u0646\u062a\u0645\u0646\u0651\u0627\u0647\u0627 \u0623\u0643\u062b\u0631 \u0645\u0646 \u063a\u064a\u0631\u0647\u0627 \u0647\u064a \u0627\u0644\u062a\u064a \u062a\u0633\u062a\u062d\u0642\u0651 \u0623\u0634\u062f\u0651 \u0627\u0644\u062a\u0645\u062d\u064a\u0635. \u0627\u0644\u0636\u064e\u0641\u064a\u0631\u0629 \u062d\u0642\u064a\u0642\u064a\u0629. \u0627\u0644\u0634\u0651\u064f\u0642\u064e\u0641 \u0627\u0644\u0645\u0646\u0642\u0648\u0634\u0629 \u062d\u0642\u064a\u0642\u064a\u0629. \u0627\u0644\u0639\u0638\u0627\u0645 \u0627\u0644\u0645\u0628\u0639\u062b\u0631\u0629 \u062d\u0642\u064a\u0642\u064a\u0629. \u0623\u0645\u0651\u0627 \u0645\u0627 \u062a\u0639\u0646\u064a\u0647 \u2014 \u0641\u0630\u0644\u0643 \u0623\u0645\u0631\u064c \u0646\u0642\u0631\u0651\u0631\u0647 \u0646\u062d\u0646."
    },
}


# ═══════════════════════════════════════════════════════════════════
#  PERSIAN VERSION
# ═══════════════════════════════════════════════════════════════════

FA_ITEM = {
    **SHARED,
    "lang": {"S": "fa"},
    "langStoryId": {"S": "fa#lots-of-the-ten"},
    "title": {"S": "\u0642\u0631\u0639\u0647\u200c\u06cc \u062f\u0647 \u0646\u0641\u0631"},
    "subtitle": {
        "S": "\u06cc\u0627\u0632\u062f\u0647 \u0633\u0641\u0627\u0644\u060c \u0633\u0647 \u0627\u0633\u06a9\u0644\u062a\u060c \u0648 \u0645\u0648\u0647\u0627\u06cc \u0628\u0627\u0641\u062a\u0647\u200c\u06cc \u0632\u0646\u06cc \u06a9\u0647 \u062f\u0648 \u0647\u0632\u0627\u0631 \u0633\u0627\u0644 \u062f\u0631 \u062e\u0627\u06a9 \u0645\u0627\u0646\u062f\u0647 \u0628\u0648\u062f \u2014 \u06a9\u0634\u0641\u06cc\u0651\u0627\u062a\u06cc \u06a9\u0647 \u0627\u0641\u0633\u0627\u0646\u0647\u200c\u06cc \u0645\u064e\u0633\u0627\u062f\u0627 \u0631\u0627 \u0647\u0645 \u062a\u0623\u06cc\u06cc\u062f \u06a9\u0631\u062f \u0648 \u0647\u0645 \u0632\u06cc\u0631 \u0633\u0624\u0627\u0644 \u0628\u064f\u0631\u062f"
    },
    "excerpt": {
        "S": "\u0648\u0642\u062a\u06cc \u0628\u0627\u0633\u062a\u0627\u0646\u200c\u0634\u0646\u0627\u0633\u0627\u0646 \u06cc\u0627\u0632\u062f\u0647 \u062a\u06a9\u0647 \u0633\u0641\u0627\u0644 \u067e\u06cc\u062f\u0627 \u06a9\u0631\u062f\u0646\u062f \u06a9\u0647 \u0631\u0648\u06cc \u0647\u0631\u06a9\u062f\u0627\u0645 \u0627\u0633\u0645\u06cc \u062d\u06a9 \u0634\u062f\u0647 \u0628\u0648\u062f \u2014 \u0627\u0632 \u062c\u0645\u0644\u0647 \u00ab\u0628\u0646 \u06cc\u0627\u0626\u06cc\u0631\u00bb \u2014 \u0641\u06a9\u0631 \u06a9\u0631\u062f\u0646\u062f \u0645\u062f\u0631\u06a9 \u0622\u062e\u0631\u06cc\u0646 \u0634\u0628 \u0645\u064e\u0633\u0627\u062f\u0627 \u0631\u0627 \u062f\u0631 \u062f\u0633\u062a \u062f\u0627\u0631\u0646\u062f. \u0627\u0645\u0627 \u0645\u0627\u062c\u0631\u0627 \u0628\u0647 \u0627\u06cc\u0646 \u0633\u0627\u062f\u06af\u06cc \u0646\u0628\u0648\u062f."
    },
    "paragraphs": make_paragraphs(
        [
            # P1
            "\u0633\u0627\u0644 \u06f1\u06f9\u06f6\u06f3\u060c \u06cc\u06cc\u06af\u0627\u0626\u0644 \u06cc\u0627\u062f\u06cc\u0646 \u0628\u0627 \u0647\u0632\u0627\u0631\u0627\u0646 \u062f\u0627\u0648\u0637\u0644\u0628 \u0627\u0632 \u0628\u06cc\u0633\u062a\u200c\u0648\u0647\u0634\u062a \u06a9\u0634\u0648\u0631 \u0627\u0632 \u062f\u0644 \u0628\u06cc\u0627\u0628\u0627\u0646 \u0628\u0627\u0644\u0627 \u0631\u0641\u062a \u062a\u0627 \u0628\u0647 \u0642\u0644\u0651\u0647\u200c\u06cc \u0645\u064e\u0633\u0627\u062f\u0627 \u0628\u0631\u0633\u062f. \u06cc\u0627\u062f\u06cc\u0646 \u06cc\u06a9 \u0628\u0627\u0633\u062a\u0627\u0646\u200c\u0634\u0646\u0627\u0633 \u0645\u0639\u0645\u0648\u0644\u06cc \u0646\u0628\u0648\u062f \u2014 \u0641\u0631\u0645\u0627\u0646\u062f\u0647\u200c\u06cc \u0627\u0631\u062a\u0634 \u0627\u0633\u0631\u0627\u0626\u06cc\u0644 \u062f\u0631 \u062c\u0646\u06af \u06f1\u06f9\u06f4\u06f8 \u0628\u0648\u062f. \u062d\u0627\u0644\u0627 \u0622\u0645\u062f\u0647 \u0628\u0648\u062f \u062f\u0698 \u0635\u062d\u0631\u0627\u06cc\u06cc\u200c\u0627\u06cc \u0631\u0627 \u0628\u06a9\u0627\u0648\u062f \u06a9\u0647 \u062f\u0631 \u0633\u0627\u0644 \u06f7\u06f3 \u0645\u06cc\u0644\u0627\u062f\u06cc \u0646\u0632\u062f\u06cc\u06a9 \u0647\u0632\u0627\u0631 \u06cc\u0647\u0648\u062f\u06cc \u062f\u0631 \u0622\u0646 \u0645\u0631\u06af \u0631\u0627 \u0628\u0647 \u062a\u0633\u0644\u06cc\u0645 \u0634\u062f\u0646 \u0628\u0647 \u0631\u0648\u0645 \u062a\u0631\u062c\u06cc\u062d \u062f\u0627\u062f\u0647 \u0628\u0648\u062f\u0646\u062f. \u0645\u0648\u0631\u0651\u062e \u0628\u0627\u0633\u062a\u0627\u0646\u060c \u06cc\u0648\u0633\u0650\u0641\u0648\u0633\u060c \u0646\u0648\u0634\u062a\u0647 \u0628\u0648\u062f \u06a9\u0647 \u0622\u062e\u0631\u06cc\u0646 \u0634\u0628 \u062f\u0647 \u0646\u0641\u0631 \u0628\u0627 \u0642\u0631\u0639\u0647 \u0627\u0646\u062a\u062e\u0627\u0628 \u0634\u062f\u0646\u062f \u062a\u0627 \u0628\u0642\u06cc\u0647 \u0631\u0627 \u0628\u06a9\u0634\u0646\u062f. \u06cc\u0627\u062f\u06cc\u0646 \u062f\u0646\u0628\u0627\u0644 \u0647\u0645\u0627\u0646 \u0642\u0631\u0639\u0647\u200c\u0647\u0627 \u0622\u0645\u062f\u0647 \u0628\u0648\u062f.",
            # P2
            "\u0648 \u0686\u06cc\u0632\u06cc \u067e\u06cc\u062f\u0627 \u06a9\u0631\u062f \u06a9\u0647 \u0647\u0645\u0647 \u0631\u0627 \u0645\u0627\u062a \u06a9\u0631\u062f. \u0646\u0632\u062f\u06cc\u06a9 \u062f\u0631\u0648\u0627\u0632\u0647\u200c\u06cc \u062c\u0646\u0648\u0628\u06cc\u060c \u062a\u06cc\u0645\u0634 \u06cc\u0627\u0632\u062f\u0647 \u062a\u06a9\u0651\u0647 \u0633\u0641\u0627\u0644 \u0627\u0632 \u062e\u0627\u06a9 \u0628\u06cc\u0631\u0648\u0646 \u06a9\u0634\u06cc\u062f \u2014 \u0631\u0648\u06cc \u0647\u0631\u06a9\u062f\u0627\u0645 \u0627\u0633\u0645\u06cc \u062e\u0631\u0627\u0634\u06cc\u062f\u0647 \u0634\u062f\u0647 \u0628\u0648\u062f. \u0631\u0648\u06cc \u06cc\u06a9\u06cc \u0646\u0648\u0634\u062a\u0647 \u0628\u0648\u062f \u00ab\u0628\u0646 \u06cc\u0627\u0626\u06cc\u0631\u00bb \u2014 \u0647\u0645\u0627\u0646 \u0646\u0627\u0645 \u0627\u0650\u0644\u0639\u0627\u0632\u0627\u0631 \u0628\u0646 \u06cc\u0627\u0626\u06cc\u0631\u060c \u0641\u0631\u0645\u0627\u0646\u062f\u0647\u200c\u0627\u06cc \u06a9\u0647 \u0645\u0631\u062f\u0645\u0634 \u0631\u0627 \u0642\u0627\u0646\u0639 \u06a9\u0631\u062f\u0647 \u0628\u0648\u062f \u0645\u0631\u06af \u0628\u0647\u062a\u0631 \u0627\u0632 \u0628\u0631\u062f\u06af\u06cc \u0627\u0633\u062a. \u06cc\u0627\u062f\u06cc\u0646 \u0646\u0648\u0634\u062a: \u00ab\u062a\u0635\u0648\u0651\u0631 \u06a9\u0646\u06cc\u062f \u0622\u0646 \u06a9\u0633\u06cc \u06a9\u0647 \u0627\u06cc\u0646 \u0642\u0631\u0639\u0647 \u0631\u0627 \u0628\u06cc\u0631\u0648\u0646 \u06a9\u0634\u06cc\u062f \u0686\u0647 \u062d\u0627\u0644\u06cc \u062f\u0627\u0634\u062a\u0647.\u00bb \u062f\u0646\u06cc\u0627 \u062e\u06cc\u0631\u0647 \u0645\u0627\u0646\u062f \u2014 \u0645\u062f\u0631\u06a9 \u0641\u06cc\u0632\u06cc\u06a9\u06cc \u062f\u0631\u0627\u0645\u0627\u062a\u06cc\u06a9\u200c\u062a\u0631\u06cc\u0646 \u0634\u0628 \u062a\u0627\u0631\u06cc\u062e \u06cc\u0647\u0648\u062f\u060c \u0647\u0645\u0627\u0646\u200c\u062c\u0627 \u0644\u0627\u06cc \u0633\u0646\u06af\u200c\u0647\u0627.",
            # P3
            "\u0627\u0645\u0627 \u067e\u0698\u0648\u0647\u0634\u06af\u0631\u0627\u0646 \u0628\u0647 \u0627\u06cc\u0646 \u0633\u0627\u062f\u06af\u06cc \u06a9\u0648\u062a\u0627\u0647 \u0646\u06cc\u0627\u0645\u062f\u0646\u062f. \u0633\u0641\u0627\u0644\u200c\u0647\u0627 \u06cc\u0627\u0632\u062f\u0647\u200c\u062a\u0627 \u0628\u0648\u062f\u060c \u0646\u0647 \u062f\u0647\u200c\u062a\u0627. \u00ab\u0628\u0646 \u06cc\u0627\u0626\u06cc\u0631\u00bb \u0627\u0633\u0645 \u0631\u0627\u06cc\u062c\u06cc \u0628\u0648\u062f \u062f\u0631 \u0642\u0631\u0646 \u0627\u0648\u0651\u0644 \u2014 \u0645\u062b\u0644 \u0627\u06cc\u0646\u06a9\u0647 \u0627\u0645\u0631\u0648\u0632 \u062f\u0631 \u06cc\u06a9 \u062d\u0641\u0651\u0627\u0631\u06cc \u00ab\u0645\u062d\u0645\u062f \u0631\u0636\u0627\u06cc\u06cc\u00bb \u067e\u06cc\u062f\u0627 \u06a9\u0646\u06cc. \u0635\u062f\u0647\u0627 \u0633\u0641\u0627\u0644 \u0645\u0634\u0627\u0628\u0647 \u062f\u0631 \u0633\u0631\u0627\u0633\u0631 \u0645\u064e\u0633\u0627\u062f\u0627 \u067e\u06cc\u062f\u0627 \u0634\u062f\u0647 \u0628\u0648\u062f \u06a9\u0647 \u0628\u0631\u0627\u06cc \u06a9\u0627\u0631\u0647\u0627\u06cc \u0631\u0648\u0632\u0645\u0631\u0651\u0647 \u0645\u062b\u0644 \u0644\u06cc\u0633\u062a \u0646\u06af\u0647\u0628\u0627\u0646\u06cc \u0648 \u0633\u0647\u0645\u06cc\u0647\u200c\u06cc \u063a\u0630\u0627 \u0627\u0633\u062a\u0641\u0627\u062f\u0647 \u0645\u06cc\u200c\u0634\u062f. \u062e\u0648\u062f\u0650 \u06cc\u0648\u0633\u0650\u0641\u0648\u0633 \u0647\u0645 \u0632\u06cc\u0631 \u0633\u0627\u06cc\u0647\u200c\u06cc \u0647\u0645\u0627\u0646 \u0627\u0645\u067e\u0631\u0627\u062a\u0648\u0631\u0647\u0627\u06cc \u0631\u0648\u0645\u06cc \u0646\u0648\u0634\u062a\u0647 \u0628\u0648\u062f \u06a9\u0647 \u0627\u0648\u0631\u0634\u0644\u06cc\u0645 \u0631\u0627 \u0648\u06cc\u0631\u0627\u0646 \u06a9\u0631\u062f\u0646\u062f. \u062e\u0648\u062f\u06a9\u0634\u06cc \u0642\u0647\u0631\u0645\u0627\u0646\u0627\u0646\u0647 \u062f\u0627\u0633\u062a\u0627\u0646 \u0628\u0647\u062a\u0631\u06cc \u0645\u06cc\u200c\u0633\u0627\u062e\u062a \u062a\u0627 \u06cc\u06a9 \u067e\u0627\u06cc\u0627\u0646 \u062f\u0631\u0647\u0645\u200c\u0648\u0628\u0631\u0647\u0645.",
            # P4
            "\u0628\u0639\u062f \u0646\u0648\u0628\u062a \u062c\u0633\u062f\u0647\u0627 \u0631\u0633\u06cc\u062f. \u062f\u0631 \u062d\u0645\u0651\u0627\u0645 \u0648\u06cc\u0631\u0627\u0646\u0647\u200c\u06cc \u06a9\u0627\u062e \u0634\u0645\u0627\u0644\u06cc\u060c \u0633\u0647 \u0627\u0633\u06a9\u0644\u062a \u067e\u06cc\u062f\u0627 \u0634\u062f: \u062c\u0648\u0627\u0646\u06cc \u062d\u062f\u0648\u062f \u0628\u06cc\u0633\u062a \u0633\u0627\u0644\u0647\u060c \u062f\u062e\u062a\u0631\u06cc \u062d\u062f\u0648\u062f \u0647\u062c\u062f\u0647 \u0633\u0627\u0644\u0647\u060c \u0648 \u06cc\u06a9 \u06a9\u0648\u062f\u06a9. \u06a9\u0646\u0627\u0631 \u062f\u062e\u062a\u0631\u060c \u0645\u0648\u0647\u0627\u06cc \u0628\u0627\u0641\u062a\u0647\u200c\u0627\u0634 \u067e\u06cc\u062f\u0627 \u0634\u062f \u2014 \u062f\u0633\u062a\u200c\u0646\u062e\u0648\u0631\u062f\u0647 \u0628\u0639\u062f \u0627\u0632 \u062f\u0648 \u0647\u0632\u0627\u0631 \u0633\u0627\u0644\u060c \u062f\u0631 \u0647\u0648\u0627\u06cc \u062e\u0634\u06a9 \u0628\u06cc\u0627\u0628\u0627\u0646 \u0646\u06af\u0647 \u062f\u0627\u0634\u062a\u0647 \u0634\u062f\u0647 \u0628\u0648\u062f. \u0645\u0648\u0647\u0627\u06cc\u0634 \u0631\u0627 \u0628\u0627\u0641\u062a\u0647 \u0628\u0648\u062f \u0648 \u0645\u06cc\u200c\u062f\u0627\u0646\u0633\u062a \u062f\u0627\u0631\u062f \u0645\u06cc\u200c\u0645\u06cc\u0631\u062f. \u062a\u0635\u0648\u06cc\u0631\u06cc \u06a9\u0647 \u0627\u0632 \u0630\u0647\u0646 \u0628\u06cc\u0631\u0648\u0646 \u0646\u0645\u06cc\u200c\u0631\u0648\u062f. \u0627\u0645\u0627 \u062f\u0631\u0633\u062a \u0647\u0645\u0627\u0646 \u0646\u0632\u062f\u06cc\u06a9\u06cc\u060c \u0627\u0633\u062a\u062e\u0648\u0627\u0646 \u062e\u0648\u06a9 \u0647\u0645 \u0628\u0648\u062f. \u06cc\u0647\u0648\u062f\u06cc\u0627\u0646 \u062e\u0648\u06a9 \u0646\u06af\u0647 \u0646\u0645\u06cc\u200c\u062f\u0627\u0634\u062a\u0646\u062f. \u0631\u0648\u0645\u06cc\u200c\u0647\u0627 \u0646\u06af\u0647 \u0645\u06cc\u200c\u062f\u0627\u0634\u062a\u0646\u062f. \u0627\u06cc\u0646\u200c\u0647\u0627 \u0648\u0627\u0642\u0639\u0627\u064b \u0645\u062f\u0627\u0641\u0639\u0627\u0646 \u0628\u0648\u062f\u0646\u062f \u2014 \u06cc\u0627 \u0633\u0631\u0628\u0627\u0632\u0647\u0627\u06cc \u0631\u0648\u0645\u06cc\u061f",
            # P5
            "\u0627\u0633\u0631\u0627\u0626\u06cc\u0644 \u0628\u0627 \u0633\u06cc\u0627\u0633\u062a \u062c\u0648\u0627\u0628 \u062f\u0627\u062f\u060c \u0646\u0647 \u0628\u0627 \u0639\u0644\u0645. \u0633\u0627\u0644 \u06f1\u06f9\u06f6\u06f9\u060c \u0628\u06cc\u0633\u062a\u200c\u0648\u0647\u0641\u062a \u062f\u0633\u062a\u0647 \u0628\u0642\u0627\u06cc\u0627\u06cc \u0627\u0646\u0633\u0627\u0646\u06cc \u0628\u0627 \u062a\u0634\u0631\u06cc\u0641\u0627\u062a \u0646\u0638\u0627\u0645\u06cc \u06a9\u0627\u0645\u0644 \u062f\u0631 \u062f\u0627\u0645\u0646\u0647\u200c\u06cc \u0645\u064e\u0633\u0627\u062f\u0627 \u0628\u0647 \u062e\u0627\u06a9 \u0633\u067e\u0631\u062f\u0647 \u0634\u062f\u0646\u062f \u2014 \u062a\u0627\u0628\u0648\u062a\u200c\u0647\u0627\u06cc \u067e\u0648\u0634\u06cc\u062f\u0647 \u0628\u0627 \u067e\u0631\u0686\u0645 \u0648 \u0634\u0644\u06cc\u06a9 \u0627\u062d\u062a\u0631\u0627\u0645. \u0645\u0631\u0627\u0633\u0645 \u0686\u06cc\u0632\u06cc \u0631\u0627 \u062d\u0642\u06cc\u0642\u062a \u0641\u0631\u0636 \u06a9\u0631\u062f \u06a9\u0647 \u0628\u0627\u0633\u062a\u0627\u0646\u200c\u0634\u0646\u0627\u0633\u06cc \u0646\u062a\u0648\u0627\u0646\u0633\u062a\u0647 \u0628\u0648\u062f \u062b\u0627\u0628\u062a\u0634 \u06a9\u0646\u062f. \u0628\u0639\u062f\u0647\u0627 \u062c\u0627\u0645\u0639\u0647\u200c\u0634\u0646\u0627\u0633 \u0646\u062d\u0645\u0627\u0646 \u0628\u0646\u200c\u06cc\u0647\u0648\u062f\u0627 \u0646\u0634\u0627\u0646 \u062f\u0627\u062f \u06a9\u0647 \u06a9\u062a\u0627\u0628\u200c\u0647\u0627\u06cc \u062f\u0631\u0633\u06cc \u06cc\u06a9 \u0648\u0627\u0642\u0639\u06cc\u062a \u062a\u0644\u062e \u0631\u0627 \u062d\u0630\u0641 \u06a9\u0631\u062f\u0647\u200c\u0627\u0646\u062f: \u0645\u062f\u0627\u0641\u0639\u0627\u0646 \u0645\u064e\u0633\u0627\u062f\u0627 \u067e\u06cc\u0634 \u0627\u0632 \u0641\u0631\u0627\u0631 \u0628\u0647 \u06a9\u0648\u0647\u060c \u0647\u0641\u062a\u0635\u062f \u06cc\u0647\u0648\u062f\u06cc\u0650 \u0631\u0648\u0633\u062a\u0627\u06cc \u0647\u0645\u0633\u0627\u06cc\u0647 \u0631\u0627 \u0642\u062a\u0644\u200c\u0639\u0627\u0645 \u06a9\u0631\u062f\u0647 \u0628\u0648\u062f\u0646\u062f. \u0627\u0641\u0633\u0627\u0646\u0647 \u0627\u0632 \u062d\u0642\u06cc\u0642\u062a \u06a9\u0627\u0631\u0622\u0645\u062f\u062a\u0631 \u0628\u0648\u062f.",
            # P6
            "\u0627\u0645\u0627 \u0645\u06cc\u0627\u0646 \u0647\u0645\u0647\u200c\u06cc \u0627\u06cc\u0646 \u062c\u0646\u062c\u0627\u0644\u200c\u0647\u0627\u060c \u062d\u0641\u0651\u0627\u0631\u06cc \u0686\u06cc\u0632\u06cc \u0628\u06cc\u0631\u0648\u0646 \u0622\u0648\u0631\u062f \u06a9\u0647 \u0647\u06cc\u0686 \u0628\u062d\u062b\u06cc \u0646\u0645\u06cc\u200c\u062a\u0648\u0627\u0646\u0633\u062a \u062e\u062f\u0634\u0647\u200c\u0627\u06cc \u0628\u0631 \u0622\u0646 \u0628\u0632\u0646\u062f. \u0645\u06cc\u0627\u0646 \u0637\u0648\u0645\u0627\u0631\u0647\u0627\u06cc \u067e\u06cc\u062f\u0627\u0634\u062f\u0647\u060c \u062a\u06a9\u0651\u0647\u200c\u0627\u06cc \u0627\u0632 \u06a9\u062a\u0627\u0628 \u062d\u0632\u0642\u06cc\u0627\u0644 \u0641\u0635\u0644 \u06f3\u06f7 \u0628\u0648\u062f \u2014 \u0631\u0624\u06cc\u0627\u06cc \u067e\u06cc\u0627\u0645\u0628\u0631 \u062f\u0631\u0628\u0627\u0631\u0647\u200c\u06cc \u062f\u0631\u0651\u0647\u200c\u0627\u06cc \u067e\u064f\u0631 \u0627\u0632 \u0627\u0633\u062a\u062e\u0648\u0627\u0646\u200c\u0647\u0627\u06cc \u062e\u0634\u06a9\u060c \u062c\u0627\u06cc\u06cc \u06a9\u0647 \u062e\u062f\u0627 \u0645\u06cc\u200c\u067e\u0631\u0633\u062f: \u00ab\u0622\u06cc\u0627 \u0627\u06cc\u0646 \u0627\u0633\u062a\u062e\u0648\u0627\u0646\u200c\u0647\u0627 \u0632\u0646\u062f\u0647 \u0645\u06cc\u200c\u0634\u0648\u0646\u062f\u061f\u00bb \u0645\u062a\u0646\u06cc \u062f\u0631\u0628\u0627\u0631\u0647\u200c\u06cc \u0631\u0633\u062a\u0627\u062e\u06cc\u0632 \u06cc\u06a9 \u0645\u0644\u0651\u062a\u060c \u062f\u0631\u0633\u062a \u062f\u0631 \u062c\u0627\u06cc\u06cc \u06a9\u0647 \u0622\u062e\u0631\u06cc\u0646 \u0645\u0642\u0627\u0648\u0645\u062a \u0622\u0646 \u0645\u0644\u0651\u062a \u062c\u0627\u0646 \u062f\u0627\u062f. \u0648 \u062f\u0631 \u0633\u0627\u0644 \u06f2\u06f0\u06f0\u06f5\u060c \u062f\u0627\u0646\u0634\u0645\u0646\u062f\u0627\u0646 \u062f\u0627\u0646\u0647\u200c\u06cc \u0646\u062e\u0644 \u062e\u0631\u0645\u0627\u06cc\u06cc \u06a9\u0627\u0634\u062a\u0646\u062f \u06a9\u0647 \u0627\u0632 \u062f\u0644\u0650 \u062d\u0641\u0651\u0627\u0631\u06cc\u200c\u0647\u0627\u06cc \u06cc\u0627\u062f\u06cc\u0646 \u0628\u06cc\u0631\u0648\u0646 \u0622\u0645\u062f\u0647 \u0628\u0648\u062f. \u062f\u0648 \u0647\u0632\u0627\u0631 \u0633\u0627\u0644 \u0639\u0645\u0631 \u062f\u0627\u0634\u062a. \u062c\u0648\u0627\u0646\u0647 \u0632\u062f\u060c \u0631\u0634\u062f \u06a9\u0631\u062f\u060c \u0648 \u0627\u0633\u0645\u0634 \u0631\u0627 \u06af\u0630\u0627\u0634\u062a\u0646\u062f \u00ab\u0645\u064e\u062a\u0648\u0634\u0627\u0644\u064e\u062d.\u00bb",
            # P7
            "\u0645\u06cc\u200c\u06af\u0648\u06cc\u0646\u062f \u0645\u064f\u0631\u062f\u0647 \u0627\u0632 \u06af\u0648\u0631 \u0628\u0631\u0646\u0645\u06cc\u200c\u06af\u0631\u062f\u062f\u060c \u0648\u0644\u06cc \u062d\u0631\u0641 \u0627\u0632 \u06af\u0648\u0631 \u0628\u0631\u0645\u06cc\u200c\u06af\u0631\u062f\u062f. \u062f\u0631 \u0645\u064e\u0633\u0627\u062f\u0627 \u0647\u0645 \u0647\u0645\u06cc\u0646 \u0634\u062f \u2014 \u0645\u064f\u0631\u062f\u0647\u200c\u0647\u0627 \u0628\u0631\u0646\u06af\u0634\u062a\u0646\u062f\u060c \u0627\u0645\u0627 \u062d\u0631\u0641\u200c\u0647\u0627\u06cc\u06cc \u06a9\u0647 \u0627\u0632 \u06af\u0648\u0631\u0634\u0627\u0646 \u0628\u06cc\u0631\u0648\u0646 \u0622\u0645\u062f \u0645\u0639\u0644\u0648\u0645 \u0646\u06cc\u0633\u062a \u062d\u0631\u0641\u0650 \u062e\u0648\u062f\u0634\u0627\u0646 \u0628\u0648\u062f \u06cc\u0627 \u0645\u0627 \u0628\u0647 \u062c\u0627\u06cc\u0634\u0627\u0646 \u062d\u0631\u0641 \u0632\u062f\u06cc\u0645. \u0633\u0641\u0627\u0644\u200c\u0647\u0627 \u0634\u0627\u06cc\u062f \u0642\u0631\u0639\u0647 \u0646\u0628\u0627\u0634\u0646\u062f. \u0627\u0633\u062a\u062e\u0648\u0627\u0646\u200c\u0647\u0627 \u0634\u0627\u06cc\u062f \u0645\u0627\u0644\u0650 \u0645\u062f\u0627\u0641\u0639\u0627\u0646 \u0646\u0628\u0627\u0634\u0646\u062f. \u062e\u0637\u0628\u0647\u200c\u0647\u0627 \u0634\u0627\u06cc\u062f \u0647\u06cc\u0686\u200c\u0648\u0642\u062a \u062e\u0648\u0627\u0646\u062f\u0647 \u0646\u0634\u062f\u0647 \u0628\u0627\u0634\u0646\u062f. \u0627\u0645\u0627 \u0637\u0648\u0645\u0627\u0631\u0647\u0627 \u0648\u0627\u0642\u0639\u06cc \u0628\u0648\u062f\u0646\u062f \u2014 \u0622\u062f\u0645\u200c\u0647\u0627\u06cc \u0648\u0627\u0642\u0639\u06cc \u0622\u0646\u200c\u0647\u0627 \u0631\u0627 \u062f\u0631 \u06a9\u0646\u06cc\u0633\u0647\u200c\u0627\u06cc \u0648\u0627\u0642\u0639\u06cc \u0628\u0627\u0644\u0627\u06cc \u06a9\u0648\u0647\u06cc \u0648\u0627\u0642\u0639\u06cc \u062e\u0648\u0627\u0646\u062f\u0647 \u0628\u0648\u062f\u0646\u062f. \u0648 \u0622\u0646 \u062f\u0627\u0646\u0647 \u0648\u0627\u0642\u0639\u06cc \u0628\u0648\u062f. \u062f\u0648 \u0647\u0632\u0627\u0631 \u0633\u0627\u0644 \u0632\u06cc\u0631 \u0622\u0648\u0627\u0631\u060c \u0645\u0646\u062a\u0638\u0631 \u0622\u0628 \u0648 \u0646\u0648\u0631. \u0622\u06cc\u0627 \u0627\u06cc\u0646 \u0627\u0633\u062a\u062e\u0648\u0627\u0646\u200c\u0647\u0627 \u0632\u0646\u062f\u0647 \u0645\u06cc\u200c\u0634\u0648\u0646\u062f\u061f \u062f\u0631 \u0645\u064e\u0633\u0627\u062f\u0627\u060c \u062d\u062a\u0651\u06cc \u062f\u0627\u0646\u0647\u200c\u0647\u0627 \u062c\u0648\u0627\u0628 \u0645\u06cc\u200c\u062f\u0647\u0646\u062f: \u0622\u0631\u06cc.",
        ]
    ),
    "moralOrLesson": {
        "S": "\u0645\u0631\u0632 \u0645\u06cc\u0627\u0646 \u06a9\u0634\u0641 \u06af\u0630\u0634\u062a\u0647 \u0648 \u0633\u0627\u062e\u062a\u0646 \u0622\u0646 \u0628\u0627\u0631\u06cc\u06a9\u200c\u062a\u0631 \u0627\u0632 \u0622\u0646 \u0627\u0633\u062a \u06a9\u0647 \u062f\u0648\u0633\u062a \u062f\u0627\u0631\u06cc\u0645 \u0628\u0627\u0648\u0631 \u06a9\u0646\u06cc\u0645. \u0647\u0631 \u0628\u0627\u0633\u062a\u0627\u0646\u200c\u0634\u0646\u0627\u0633\u06cc \u06a9\u0647 \u0686\u06cc\u0632\u06cc \u0627\u0632 \u062f\u0644 \u062e\u0627\u06a9 \u0628\u06cc\u0631\u0648\u0646 \u0645\u06cc\u200c\u0622\u0648\u0631\u062f\u060c \u0627\u0646\u062a\u062e\u0627\u0628 \u0645\u06cc\u200c\u06a9\u0646\u062f \u0686\u0647 \u062f\u0627\u0633\u062a\u0627\u0646\u06cc \u0627\u0632 \u0622\u0646 \u0628\u0633\u0627\u0632\u062f \u2014 \u0648 \u0622\u0646 \u062f\u0627\u0633\u062a\u0627\u0646\u200c\u0647\u0627\u06cc\u06cc \u06a9\u0647 \u0628\u06cc\u0634\u062a\u0631 \u0627\u0632 \u0647\u0645\u0647 \u062f\u0644\u0645\u0627\u0646 \u0645\u06cc\u200c\u062e\u0648\u0627\u0647\u062f \u0648\u0627\u0642\u0639\u06cc \u0628\u0627\u0634\u0646\u062f\u060c \u0647\u0645\u0627\u0646\u200c\u0647\u0627\u06cc\u06cc \u0647\u0633\u062a\u0646\u062f \u06a9\u0647 \u0628\u0627\u06cc\u062f \u0628\u06cc\u0634\u062a\u0631 \u0627\u0632 \u0647\u0645\u0647 \u0632\u06cc\u0631 \u0630\u0631\u0651\u0647\u200c\u0628\u06cc\u0646 \u0628\u0628\u0631\u06cc\u0645. \u0645\u0648\u0647\u0627\u06cc \u0628\u0627\u0641\u062a\u0647 \u0648\u0627\u0642\u0639\u06cc\u200c\u0627\u0646\u062f. \u0633\u0641\u0627\u0644\u200c\u0647\u0627\u06cc \u062d\u06a9\u200c\u0634\u062f\u0647 \u0648\u0627\u0642\u0639\u06cc\u200c\u0627\u0646\u062f. \u0627\u0633\u062a\u062e\u0648\u0627\u0646\u200c\u0647\u0627\u06cc \u067e\u0631\u0627\u06a9\u0646\u062f\u0647 \u0648\u0627\u0642\u0639\u06cc\u200c\u0627\u0646\u062f. \u0627\u0645\u0627 \u0645\u0639\u0646\u0627\u06cc\u0634\u0627\u0646 \u2014 \u0622\u0646 \u0631\u0627 \u0645\u0627 \u062a\u0639\u06cc\u06cc\u0646 \u0645\u06cc\u200c\u06a9\u0646\u06cc\u0645."
    },
}


# ─── Validate JSON structure ───
def validate_item(item, lang):
    """Ensure all required fields exist and paragraphs are well-formed."""
    required = [
        "siteId", "storyId", "lang", "langStoryId", "title", "subtitle",
        "excerpt", "paragraphs", "moralOrLesson", "icon", "tier", "source",
        "characters", "era", "readingTimeMinutes", "image", "thumbnail",
        "disabled", "coordinates", "hasAudio", "isFree", "storyCategory",
        "updatedAt",
    ]
    missing = [f for f in required if f not in item]
    if missing:
        print(f"  [{lang}] MISSING FIELDS: {missing}")
        return False

    paras = item["paragraphs"]["L"]
    if not (6 <= len(paras) <= 10):
        print(f"  [{lang}] Paragraph count {len(paras)} out of range 6-10")
        return False

    for i, p in enumerate(paras):
        text = p["M"]["text"]["S"]
        if len(text) > 600:
            print(f"  [{lang}] P{i+1} exceeds 600 chars ({len(text)})")
            return False

    total_chars = sum(len(p["M"]["text"]["S"]) for p in paras)
    print(f"  [{lang}] Paragraphs: {len(paras)}, Total chars: {total_chars}")

    # Validate JSON serialization round-trip
    try:
        serialized = json.dumps(item, ensure_ascii=False)
        json.loads(serialized)
    except Exception as e:
        print(f"  [{lang}] JSON validation failed: {e}")
        return False

    print(f"  [{lang}] JSON validation passed")
    return True


# ─── Push to DynamoDB ───
def push_item(item, lang):
    print(f"\n{'='*50}")
    print(f"  Pushing {lang.upper()} version...")
    print(f"{'='*50}")

    if not validate_item(item, lang):
        print(f"  [{lang}] VALIDATION FAILED — aborting push")
        return False

    try:
        dynamodb.put_item(TableName=TABLE, Item=item)
        print(f"  [{lang}] Push SUCCESSFUL")
    except Exception as e:
        print(f"  [{lang}] Push FAILED: {e}")
        return False

    # Verify the record exists
    try:
        resp = dynamodb.get_item(
            TableName=TABLE,
            Key={
                "siteId": {"S": SITE_ID},
                "langStoryId": {"S": f"{lang}#{STORY_ID}"},
            },
        )
        if "Item" in resp:
            title = resp["Item"]["title"]["S"]
            n_paras = len(resp["Item"]["paragraphs"]["L"])
            print(f"  [{lang}] VERIFIED — title: {title}, paragraphs: {n_paras}")
            return True
        else:
            print(f"  [{lang}] VERIFICATION FAILED — item not found after push")
            return False
    except Exception as e:
        print(f"  [{lang}] Verification error: {e}")
        return False


# ─── Main ───
if __name__ == "__main__":
    print(f"Timestamp: {NOW_TS}")
    results = {}

    for lang, item in [("ar", AR_ITEM), ("fa", FA_ITEM)]:
        results[lang] = push_item(item, lang)

    print(f"\n{'='*50}")
    print("  SUMMARY")
    print(f"{'='*50}")
    all_ok = True
    for lang, ok in results.items():
        status = "OK" if ok else "FAILED"
        print(f"  {lang}: {status}")
        if not ok:
            all_ok = False

    sys.exit(0 if all_ok else 1)
